import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.HttpEntity;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpMethod;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestHeader;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.client.RestTemplate;
import org.springframework.web.util.UriComponentsBuilder;

@RestController
public class WebhookController {
    @Autowired
    private RestTemplate restTemplate;

    @PostMapping("/webhooks")
    public ResponseEntity<String> handleWebhook(@RequestBody String payload, @RequestHeader("X-API-Key") String apiKey) {
        if (!"your_api_key".equals(apiKey)) {
            return ResponseEntity.status(401).body("Invalid API Key");
        }

        UriComponentsBuilder builder = UriComponentsBuilder.fromUriString(payload);
        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(org.springframework.http.MediaType.APPLICATION_JSON);

        ResponseEntity<String> response;
        try {
            response = restTemplate.exchange(builder.build().toUri(), HttpMethod.GET, null, String.class);
        } catch (Exception e) {
            return ResponseEntity.status(500).body("Error fetching content: " + e.getMessage());
        }

        return response;
    }
}